const Q_PHYSICS_1997=[{"id": "objective>Physics>1997>1", "question": "<div style=\"font-family:Cambria;font-size:17px;\">At what respective values of X, Y and Z would the unit of force, the newton, be dimensionally equivalent to M<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">x</span>L<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">y</span>T<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">z</span>?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\"> -1, 1, 2</div>", "<div style=\"font-family:Cambria;font-size:17px;\">1, 1, -2</div>", "<div style=\"font-family:Cambria;font-size:17px;\">1, -1, 2</div>", "<div style=\"font-family:Cambria;font-size:17px;\">-1, 1, -2</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The dimensional formula for force (Newton) is MLT<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-2</span>. This means that the power of M (mass) is 1, the power of L (length) is 1, and the power of T (time) is -2. Therefore, the respective values of X, Y, and Z are 1, 1, and -2.</div>", "topic": "MEASUREMENTS AND UNITS : DIMENSIONS"}, {"id": "objective>Physics>1997>2", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The distance xm travelled by a particle in time t seconds is described by the equation x = 10 + 12t<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span>, Find the average speed of the particle between the time interval t = 2s and t = 5s</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">60 ms<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-1</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">72 ms<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-1</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">84 ms<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-1</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">108 ms<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-1</span></div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">x = 10 + 12t<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span> <br/> At t<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span> = 2 s <br/> x(2) = 10 + 12(2)<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span> = 58 <br/> At t<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span> = 5 s <br/> x(2) = 10 + 12(5)<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span> = 310 <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">Average</td><td style=\"text-align:center;\">speed</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">x(5) - x(2)<hr size=\"1\" />t<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span> - t<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span></td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">310 - 58<hr size=\"1\" />5 - 2</td></tr></table></div> <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">252<hr size=\"1\" />3</td></tr></table></div> <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">84</td><td style=\"text-align:center;\">ms<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-1</span></td></tr></table></div></div>", "topic": "MOTION: LINEAR MOTION"}, {"id": "objective>Physics>1997>3", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A 5kg block is released from rest on a smooth plane inclined at an angle of 30<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">o</span> to the horizontal. What is the acceleration down the plane? [g = 10ms<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-2</span>]</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">5.0 ms<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-2</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">5.8 ms<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-2</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">8.7 ms<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-2</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">25.0 ms<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-2</span></div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">ma = mgsinθ <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">a</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">5×10×sin30<hr size=\"1\" />m</td></tr></table></div> <br/> a = 5ms<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-2</span></div>", "topic": "MOTION : NEWTON’S LAWS OF MOTION~~MOTION: MOTION UNDER GRAVITY"}, {"id": "objective>Physics>1997>4", "question": "<div style=\"font-family:Cambria;font-size:17px;\">An arrow of mass 0.1kg moving with a horizontal velocity of 15ms<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-1</span> is shot into a wooden block of mass 0.4kg lying at rest on a smooth horizontal surface. Their common velocity after impact is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">15.0 ms<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-1</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">7.5 ms<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-1</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">3.8 ms<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-1</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">3.0 ms<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-1</span></div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">M<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span>U<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span> + M<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>U<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span> = (M<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span> + M<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>)V <br/> 0.1(15) = (0.1 + 0.4)V <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">v</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">1.5<hr size=\"1\" />0.5</td></tr></table></div> <br/> v = 3ms<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-1</span></div>", "topic": "MOTION : NEWTON’S LAWS OF MOTION"}, {"id": "objective>Physics>1997>5", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Two bodies X and Y are projected on the same horizontal plane, with the same initial speed but at angles 30 and 60 respectively to the horizontal. Neglecting air resistance, the ratio of the range of X to that of Y is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">1:1</div>", "<div style=\"font-family:Cambria;font-size:17px;\">1:2</div>", "<div style=\"font-family:Cambria;font-size:17px;\">√3:1</div>", "<div style=\"font-family:Cambria;font-size:17px;\">√3</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\"><div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">Range</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">U<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span>sin2θ<hr size=\"1\" />g</td></tr></table></div> <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">R<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">x</span><hr size=\"1\" />R<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">y</span></td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">U<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">x</span><span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span>sin60<hr size=\"1\" />U<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">y</span><span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span>sin120</td></tr></table></div> <br/> sin60 = sin120 <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">R<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">x</span><hr size=\"1\" />R<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">y</span></td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">1<hr size=\"1\" />1</td></tr></table></div></div>", "topic": "MOTION: PROJECTILES"}, {"id": "objective>Physics>1997>6", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following with respect to a body performing simple harmonic motion are in phase?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">displacement and velocity of the body</div>", "<div style=\"font-family:Cambria;font-size:17px;\">displacement and force on the body</div>", "<div style=\"font-family:Cambria;font-size:17px;\">velocity and acceleration of the body</div>", "<div style=\"font-family:Cambria;font-size:17px;\">force acting on the body and the acceleration</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">In simple harmonic motion, the velocity and acceleration of the body are in phase. This means that they reach their maximum and minimum values at the same time. The displacement and velocity are 90 degrees out of phase, meaning that when one is at its maximum, the other is at zero. The displacement and force are 180 degrees out of phase, meaning that they are always in opposite directions. The force and acceleration are in phase because force is proportional to acceleration (F = ma).</div>", "topic": "MOTION: SIMPLE HARMONIC MOTION (S.H.M)"}, {"id": "objective>Physics>1997>7", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A body of mass 2kg moving vertically upwards has its velocity increased uniformly from 10ms<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-1</span> to 40ms<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-1</span> in 4s. Neglecting air resistance, calculate the upward vertical force acting on the body.[g = 10 ms<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-1</span>]</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">15N</div>", "<div style=\"font-family:Cambria;font-size:17px;\">20N</div>", "<div style=\"font-family:Cambria;font-size:17px;\">35N</div>", "<div style=\"font-family:Cambria;font-size:17px;\">45N</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The force acting on the body can be calculated using the second law of motion, which states that the force acting on an object is equal to its mass times its acceleration. The acceleration of the body can be calculated using the formula a = (v - u) / t, where v is the final velocity, u is the initial velocity, and t is the time. Substituting the given values, we get a = (40 - 10) / 4 = 7.5 m/s^2. The force is then F = m * a = 2 * 7.5 = 15 N. However, the body is moving upwards against gravity, so the net force acting on the body is the sum of the force due to its acceleration and the force due to gravity, which is m * g = 2 * 10 = 20 N. Therefore, the total force is 15 N + 20 N = 35 N.</div>", "topic": "MOTION : NEWTON’S LAWS OF MOTION"}, {"id": "objective>Physics>1997>8", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A planet has mass m<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span> and is at a distance r, from the sun. A second planet has mass m<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span> = 10m<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span> and at a distance of r<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span> = 2r<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span> from the sun. Determine the ratio of the gravitational force experienced by the planets.</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">1:5</div>", "<div style=\"font-family:Cambria;font-size:17px;\">2:5</div>", "<div style=\"font-family:Cambria;font-size:17px;\">3:5</div>", "<div style=\"font-family:Cambria;font-size:17px;\">4:5</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\"><div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">g</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">GM<hr size=\"1\" />R<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span></td></tr></table></div> <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">G<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span>M<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span><hr size=\"1\" />r<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span><span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span></td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\"></td><td style=\"text-align:center;\">G<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>M<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span><hr size=\"1\" />r<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span><span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span></td></tr></table></div> <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">G<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span>M<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span><hr size=\"1\" />r<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span><span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span></td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\"></td><td style=\"text-align:center;\">G<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>(10M<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span>)<hr size=\"1\" />(2r<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span>)<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span></td></tr></table></div> <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">G<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span><hr size=\"1\" />G<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span></td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">2<hr size=\"1\" />5</td></tr></table></div></div>", "topic": "GRAVITATIONAL FIELD"}, {"id": "objective>Physics>1997>9", "question": "<div style=\"font-family:Cambria;font-size:17px;\">An object of mass 100g projected vertically upwards from the ground level has a velocity of 20ms<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-1</span> at a height of 10m. calculate its initial kinetic energy at the ground level. <br/> [g = 10ms<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-2</span>, neglect air resistance]</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">10J</div>", "<div style=\"font-family:Cambria;font-size:17px;\">20J</div>", "<div style=\"font-family:Cambria;font-size:17px;\">30J</div>", "<div style=\"font-family:Cambria;font-size:17px;\">50J</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">v<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span> = u<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span> - 2gx <br/> 20<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span> = u<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span> - 2(10)(10) <br/> u<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span> = 400 + 200 <br/> u<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span> = 600 m/s  <br/> initial kinetic energy <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">K.E</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">1<hr size=\"1\" />2</td><td style=\"text-align:center;\">mu<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span></td></tr></table></div> <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">K.E</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">1<hr size=\"1\" />2</td><td style=\"text-align:center;\">×</td><td style=\"text-align:center;\">0.1</td><td style=\"text-align:center;\">×</td><td style=\"text-align:center;\">600</td></tr></table></div> <br/> K.E = 30J</div>", "topic": "MOTION: MOTION UNDER GRAVITY~~WORK, ENERGY AND POWER"}, {"id": "objective>Physics>1997>10", "question": "<div style=\"font-family:Cambria;font-size:17px;\">An electric water pump rate 1.5 kW, lifts 200kg of water through a vertical height of 6 meters in 10 seconds. What is the efficiency of the pump?  <br/> [g = 10ms<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-2</span>, neglecting air resistance]</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">90.0%</div>", "<div style=\"font-family:Cambria;font-size:17px;\">85.0%</div>", "<div style=\"font-family:Cambria;font-size:17px;\">80.0%</div>", "<div style=\"font-family:Cambria;font-size:17px;\">65.0%</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\"><div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">efficiency</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">output<hr size=\"1\" />input</td><td style=\"text-align:center;\">×</td><td style=\"text-align:center;\">100</td></tr></table></div> <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">output</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">200(10)(6)<hr size=\"1\" />10</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">1200W</td></tr></table></div> <br/> input = 1500W <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">Efficiency</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">1200<hr size=\"1\" />1500</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">80%</td></tr></table></div></div>", "topic": "WORK, ENERGY AND POWER: POWER"}, {"id": "objective>Physics>1997>11", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A load of 20N on a wire of cross-sectional area 8 x 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-7</span> m<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span>, produces an extension of 10m<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span>. calculate Young's modulus for the material of the wire if its length is 3m</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">7.0 x 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">11</span>Nm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-2</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">7.5 x 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">11</span>Nm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-2</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">8.5 x 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">11</span>Nm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-2</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">9.0 x 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">11</span>Nm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-2</span></div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\"><div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">Young's</td><td style=\"text-align:center;\">modulus</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">F<hr size=\"1\" />A</td><td style=\"text-align:center;\">÷</td><td style=\"text-align:center;\">e<hr size=\"1\" />L</td></tr></table></div> <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">20<hr size=\"1\" />8×10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-7</span></td><td style=\"text-align:center;\">÷</td><td style=\"text-align:center;\">10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-4</span><hr size=\"1\" />3</td></tr></table></div> <br/> 7.5 × 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">11</span> Nm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-2</span></div>", "topic": "ELASTICITY"}, {"id": "objective>Physics>1997>12", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A cube of sides 0.1m hangs freely from a string. What is the upthrust on the cube when totally immersed in water? <br/>  [density of water is 1000kgm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-2</span>, g = 10ms<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-2</span>]</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">1000N</div>", "<div style=\"font-family:Cambria;font-size:17px;\">700N</div>", "<div style=\"font-family:Cambria;font-size:17px;\">110N</div>", "<div style=\"font-family:Cambria;font-size:17px;\">10N</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">volume of the cube = 0.1<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span> = 1 × 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-3</span> m<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span> <br/> u = vρg <br/> = 1 × 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-3</span> × 1000 × 10 <br/> = 10N</div>", "topic": "LIQUIDS AT REST : UPTHRUST"}, {"id": "objective>Physics>1997>13", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A piece of wire gauze can be made to lie on water because</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">the wire guaze is less dense than water</div>", "<div style=\"font-family:Cambria;font-size:17px;\">the water molecules repels the wire guaze upwards</div>", "<div style=\"font-family:Cambria;font-size:17px;\"> the water surface has the effect of an elastic thin skin</div>", "<div style=\"font-family:Cambria;font-size:17px;\">of the cohensive forces between the water and the wire guaze molecules</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">A piece of wire gauze can be made to lie on water because the water surface has the effect of an elastic thin skin (surface tension)</div>", "topic": "STRUCTURE OF MATTER AND KINETIC THEORY : MOLECULAR NATURE OF MATTER"}, {"id": "objective>Physics>1997>14", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A liquid of mass 1.0 x 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span>kg fills a rectangular tank of length 2.5m and width 2.0m. If the tank is 4m high, what is the pressure at the middle of the tank? <br/> [g = 10ms<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-2</span>]</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">1.0 x 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">4</span>Nm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-2</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">2.0 x 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span>Nm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-2</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">1.5 x 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span>Nm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-2</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">1.0 x 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span>Nm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-2</span></div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\"><div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">Density</td><td style=\"text-align:center;\">of</td><td style=\"text-align:center;\">liquid</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">1×10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span><hr size=\"1\" />2.5×2×4</td></tr></table></div> <br/> = 50kgm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-3</span> <br/> Pressure = ρgh <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">Pressure</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">50</td><td style=\"text-align:center;\">×</td><td style=\"text-align:center;\">10</td><td style=\"text-align:center;\">×</td><td style=\"text-align:center;\">4<hr size=\"1\" />2</td></tr></table></div> <br/> 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span> Nm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-2</span></div>", "topic": "PRESSURE : PRESSURE IN LIQUIDS"}, {"id": "objective>Physics>1997>15", "question": "<div style=\"font-family:Cambria;font-size:17px;\">An empty 60 litre petrol tank has a mass of 10kg. Its mass when full of fuel of relative density 0.72 is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">7.2kg</div>", "<div style=\"font-family:Cambria;font-size:17px;\">33.2kg</div>", "<div style=\"font-family:Cambria;font-size:17px;\">43.2kg</div>", "<div style=\"font-family:Cambria;font-size:17px;\">53.2kg</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Let mass of tank when full = x <br/>  <br/> mass of petrol in the tank = x - 10 <br/>  <br/> volume of water in the tank = 60l = 60,000 cm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span> <br/>  <br/> since 1 cm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span> of water = 1 g of water, <br/>  <br/> ∴ 60,000 cm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span> of water = 60,000 g of water <br/>  <br/> so, <br/>  <br/> mass of water = 60,000 g = 60 kg <br/>  <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">R.d</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">mass of petrol<hr size=\"1\" />mass of equal volume of water</td></tr></table></div> <br/> 0.72 = <span class = \"katex\"><span class = \"katex-mathml\"><math xmlns = \"http://www.w3.org/1998/Math/MathML\"><semantics><mrow><mfrac><mrow><mi>x</mi><mo>−</mo><mn>10</mn></mrow><mn>60</mn></mfrac></mrow><annotation encoding = \"application/x-tex\">\\frac{x-10}{60}</annotation></semantics></math></span><span class = \"katex-html\" aria-hidden = \"true\"><span class = \"base\"><span class = \"strut\" style = \"height:1.1901em;vertical-align:-0.345em;\"></span><span class = \"mord\"><span class = \"mopen nulldelimiter\"></span><span class = \"mfrac\"><span class = \"vlist-t vlist-t2\"><span class = \"vlist-r\"><span class = \"vlist\" style = \"height:0.8451em;\"><span style = \"top:-2.655em;\"><span class = \"pstrut\" style = \"height:3em;\"></span><span class = \"sizing reset-size6 size3 mtight\"><span class = \"mord mtight\"><span class = \"mord mtight\">60</span></span></span></span><span style = \"top:-3.23em;\"><span class = \"pstrut\" style = \"height:3em;\"></span><span class = \"frac-line\" style = \"border-bottom-width:0.04em;\"></span></span><span style = \"top:-3.394em;\"><span class = \"pstrut\" style = \"height:3em;\"></span><span class = \"sizing reset-size6 size3 mtight\"><span class = \"mord mtight\"><span class = \"mord mathnormal mtight\">x</span><span class = \"mbin mtight\">−</span><span class = \"mord mtight\">10</span></span></span></span></span><span class = \"vlist-s\">​</span></span><span class = \"vlist-r\"><span class = \"vlist\" style = \"height:0.345em;\"><span></span></span></span></span></span><span class = \"mclose nulldelimiter\"></span></span></span></span></span> <br/>  <br/> 43.2 = x - 10 <br/>  <br/> ∴ x = 43.2 + 10 = 53.2 kg</div>", "topic": "LIQUIDS AT REST : RELATIVE DENSITY"}, {"id": "objective>Physics>1997>16", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The length of mercury thread when it is at 0°C, 100°C and at an unknown temperature θ is 25mm, 225mm and 175mm respectively. The value of θ is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">85.0<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">o</span>C</div>", "<div style=\"font-family:Cambria;font-size:17px;\">80.0<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">o</span>C</div>", "<div style=\"font-family:Cambria;font-size:17px;\">75.0<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">o</span>C</div>", "<div style=\"font-family:Cambria;font-size:17px;\">70.0<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">o</span>C</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\"><div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">100-0<hr size=\"1\" />θ-0</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">225-25<hr size=\"1\" />175-25</td></tr></table></div> <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">100<hr size=\"1\" />θ</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">200<hr size=\"1\" />150</td></tr></table></div> <br/> 1500 = 20θ <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">θ</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">1500<hr size=\"1\" />20</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">75<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">o</span>C</td></tr></table></div></div>", "topic": "TEMPERATURE AND ITS MEASUREMENT"}, {"id": "objective>Physics>1997>17", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Equal masses of copper and rubber are raised to the same temperature. After sometimes, the copper was observed to be at a lower temperature because</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\"> the specific heat capacity of copper is lower than that of rubber</div>", "<div style=\"font-family:Cambria;font-size:17px;\">copper expands more than rubber</div>", "<div style=\"font-family:Cambria;font-size:17px;\">the specific heat capacity of rubber is lower than that of copper</div>", "<div style=\"font-family:Cambria;font-size:17px;\">rubber expands more than copper</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The specific heat capacity of a substance is the amount of heat required to raise the temperature of one kilogram of the substance by one degree Celsius. If equal masses of copper and rubber are raised to the same temperature, the copper will cool down faster than the rubber if the specific heat capacity of copper is lower than that of rubber. This is because a substance with a lower specific heat capacity requires less heat to increase its temperature, and therefore also loses heat faster. The correct option is 'the specific heat capacity of copper is lower than that of rubber'.</div>", "topic": "QUANTITY OF HEAT : HEAT CAPACITY AND SPECIFIC HEAT CAPACITY"}, {"id": "objective>Physics>1997>18", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Before starting a journey, the tyre pressure of a car was 3 x 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">5</span>Nm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-2</span> at 27<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">o</span>C. At the end of the journey, the pressure rose to 4 x 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">5</span>Nm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-2</span>. Calculate the temperature of the tyre after the journey, assuming the volume is constant</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">400<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">o</span>C</div>", "<div style=\"font-family:Cambria;font-size:17px;\">300<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">o</span>C</div>", "<div style=\"font-family:Cambria;font-size:17px;\">273<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">o</span>C</div>", "<div style=\"font-family:Cambria;font-size:17px;\">127<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">o</span>C</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\"><div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">P<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span><hr size=\"1\" />T<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span></td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">P<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span><hr size=\"1\" />T<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span></td></tr></table></div> <br/> T<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span> = 27 + 273 = 300K <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">3×10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">6</span><hr size=\"1\" />300</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">4×10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">6</span><hr size=\"1\" />T<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span></td></tr></table></div> <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">T<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span></td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">4×10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">6</span>×300<hr size=\"1\" />3×10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">6</span></td></tr></table></div> <br/> T<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span> = 400K <br/> T<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span> = 400 - 273 = 127<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">∘</span>C</div>", "topic": "GAS LAWS"}, {"id": "objective>Physics>1997>19", "question": "<div style=\"font-family:Cambria;font-size:17px;\">What happens when a, certain quantity of pure ice is completely changed to water at 0<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">o</span>C?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">latent heat is absorbed, the mass remains constant, and the volume decreases</div>", "<div style=\"font-family:Cambria;font-size:17px;\">latent heat is given out, the mass remains constant and the volume decreases</div>", "<div style=\"font-family:Cambria;font-size:17px;\">latent heat is given out, the mass increases and the volume remains constant</div>", "<div style=\"font-family:Cambria;font-size:17px;\">latent heat is absorbed, the mass decreases and the volume increases</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">When ice is changed to water at 0<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">o</span>C, latent heat is absorbed. Latent heat is the heat energy required to change the state of a substance without changing its temperature. The mass remains constant because the number of molecules of water remains the same. The volume decreases because water has a smaller volume than ice for the same mass.</div>", "topic": "CHANGE OF STATE"}, {"id": "objective>Physics>1997>20", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A heating coil rated at 100W is used to boil off 0.5kg of boiling water. The time taken to boil off the water is  <br/> [specific latent heat of vaporization of water = 2.3 x 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">6</span>Jkg<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-1</span>]</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">1.15 x 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">9</span> s</div>", "<div style=\"font-family:Cambria;font-size:17px;\">1.15 x 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">7</span> s</div>", "<div style=\"font-family:Cambria;font-size:17px;\">1.15 x 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">5</span> s</div>", "<div style=\"font-family:Cambria;font-size:17px;\">1.15 x 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">4</span> s</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Heat energy = Electrical energy <br/> 0.5 × 2.3 × 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">6</span> = 100t <br/> t = 1.15 × 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">4</span>s</div>", "topic": "CHANGE OF STATE : SPECIFIC LATENT HEATS OF VAPORIZATION"}, {"id": "objective>Physics>1997>21", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A mass of a liquid at 30<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">o</span>C is mixed with a mass of the same liquid at 70<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">o</span>C and the temperature of the mixture is 45<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">o</span>C. Find the ratio of the mass of the cold liquid to the mass of the other liquid.</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">3 : 5</div>", "<div style=\"font-family:Cambria;font-size:17px;\">5 : 3</div>", "<div style=\"font-family:Cambria;font-size:17px;\">3 : 7</div>", "<div style=\"font-family:Cambria;font-size:17px;\">7 : 3</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Heat loss = heat gained  <br/> m<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">H</span> × c × (70 - 45) = m<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">c</span> × c × (45 - 30) <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">m<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">c</span><hr size=\"1\" />m<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">H</span></td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">5<hr size=\"1\" />3</td></tr></table></div></div>", "topic": "QUANTITY OF HEAT : HEAT CAPACITY AND SPECIFIC HEAT CAPACITY"}, {"id": "objective>Physics>1997>22", "question": "<div style=\"font-family:Cambria;font-size:17px;\">What happens when a gas expands at constant temperature?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">its pressure decreases</div>", "<div style=\"font-family:Cambria;font-size:17px;\">the total momentum of its molecules remains constant</div>", "<div style=\"font-family:Cambria;font-size:17px;\">its pressure decreases and the total momentum of its moleculees remains constant</div>", "<div style=\"font-family:Cambria;font-size:17px;\">its pressure decreses and the total kinetic energy of its molecule decreases</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">According to Boyle's law, at constant temperature, the volume of a gas is inversely proportional to its pressure. Therefore, when a gas expands at constant temperature, its pressure decreases.</div>", "topic": "GAS LAWS"}, {"id": "objective>Physics>1997>23", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Ripples on water and light waves are similar because both?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">have the same frequency</div>", "<div style=\"font-family:Cambria;font-size:17px;\">can be refracted and diffracted</div>", "<div style=\"font-family:Cambria;font-size:17px;\">are longitudinal waves</div>", "<div style=\"font-family:Cambria;font-size:17px;\">have the same velocity</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Examples of transverse waves include: <br/> -- ripples on the surface of water. <br/> - vibrations in a guitar string. <br/> - electromagnetic waves – eg light waves, microwaves, radio waves. <br/> Some basic properties of light : <br/> - Reflection of light. <br/> - Refraction of light. <br/> - Diffraction of light. <br/> All kinds of waves have the same fundamental properties of reflection, refraction, diffraction and interference, and all waves have a wavelength, frequency, speed and amplitude.</div>", "topic": "WAVES : CHARACTERISTICS/PROPERTIES"}, {"id": "objective>Physics>1997>24", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Under constant tension and constant mass per unit length, the note produced by a plucked string is 500Hz when the length of the string is 0.90m. At what length is the frequency 150Hz?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">3m</div>", "<div style=\"font-family:Cambria;font-size:17px;\">4m</div>", "<div style=\"font-family:Cambria;font-size:17px;\">5m</div>", "<div style=\"font-family:Cambria;font-size:17px;\">6m</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\"><div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">F</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">1<hr size=\"1\" />2L</td><td style=\"text-align:center;\">&radic;<span style=\"margin: 0;padding:0;border-top:solid black 1px;\"></td><td style=\"text-align:center;\">T<hr size=\"1\" />m</td><td style=\"text-align:center;\">&nbsp;</span></td></tr></table></div>  <br/> F<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span>L<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span> = F<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>L<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span> <br/> 500 x 0.9 = 150 x L<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span> <br/> therefore, L<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span> = 3m</div>", "topic": "PROPAGATION OF SOUND WAVES"}, {"id": "objective>Physics>1997>25", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The colours seen in the thin films of oil on the road and in soap bubbles are due to</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">reflection</div>", "<div style=\"font-family:Cambria;font-size:17px;\">interference</div>", "<div style=\"font-family:Cambria;font-size:17px;\">diffraction</div>", "<div style=\"font-family:Cambria;font-size:17px;\">polarization</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">A simple form of interference pattern is obtained if two plane waves of the same frequency intersect at an angle. Interference is essentially an energy redistribution process.</div>", "topic": "WAVES : CHARACTERISTICS/PROPERTIES"}, {"id": "objective>Physics>1997>26", "question": "<div style=\"font-family:Cambria;font-size:17px;\">If the load at the end of a sonometer wire is immersed in a bucket of water, the original fundamental frequency of the wire could be restored by</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">decrease the length of the wire</div>", "<div style=\"font-family:Cambria;font-size:17px;\">increasing the length of the wire</div>", "<div style=\"font-family:Cambria;font-size:17px;\">increasing the mass per unit length of the wire</div>", "<div style=\"font-family:Cambria;font-size:17px;\">changing the temperature of the wire</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The fundamental frequency of a wire is inversely proportional to its length. When the load is immersed in water, the tension in the wire changes due to the buoyancy effect. To restore the original fundamental frequency, you can decrease the length of the wire, which will increase the frequency.</div>", "topic": "PROPAGATION OF SOUND WAVES"}, {"id": "objective>Physics>1997>27", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A boy on looking into a mirror observed that his face appeared to have grown bigger. The boy must have been looking at a</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">convex mirror with his face at the focus</div>", "<div style=\"font-family:Cambria;font-size:17px;\">concave mirror with his face between the focus and the mirror</div>", "<div style=\"font-family:Cambria;font-size:17px;\">concave mirror with his face at the focus</div>", "<div style=\"font-family:Cambria;font-size:17px;\">convex mirror with his face between the focus and the mirror</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">When an object lies between focus and centre of curvature, then a real, inverted and enlarged image is formed by the concave mirror.</div>", "topic": "REFLECTION OF LIGHT AT PLANE AND CURVED SURFACES : FORMATION OF IMAGES BY PLANE, CONCAVE AND CONVEX MIRRORS AND RAY DIAGRAMS"}, {"id": "objective>Physics>1997>28", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Light of velocity 3 x 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">8</span>ms<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-1</span> is incident on a material of reflective of index n. If the velocity of light is reduced to 2.4 x 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">8</span>ms<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-1</span> in the material, what is n?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">2.33</div>", "<div style=\"font-family:Cambria;font-size:17px;\">2.25</div>", "<div style=\"font-family:Cambria;font-size:17px;\">1.33</div>", "<div style=\"font-family:Cambria;font-size:17px;\">1.25</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The refractive index of a material is given by the ratio of the speed of light in vacuum to the speed of light in the material. Therefore, n = c/v = 3 x 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">8</span>ms<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-1</span> / 2.4 x 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">8</span>ms<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-1</span> = 1.25.</div>", "topic": "REFRACTION OF LIGHT THROUGH : PLANE AND CURVED SURFACE"}, {"id": "objective>Physics>1997>29", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The electromagnetic waves that are sensitive to temperature changes are</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">X-rays</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Gamma-rays</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Ultra-violet rays</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Infra-red rays</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Infra-red rays are known to be sensitive to temperature changes. This is because they are absorbed by objects, causing the objects to heat up.</div>", "topic": "WAVES : CLASSIFICATION"}, {"id": "objective>Physics>1997>30", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Three electric cells each of e.m.f 1.5V and internal resistance of 1.0Ω are connected in parallel across an external resistance of <span style=\"position: relative;left:3px;top:-7px; font-size:15px;\">2</span>/<span style=\"position:relative;left:-3px;top:7px;font-size:15px;\">3</span> Ω. Calculate the value of the current in the resistor</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">0.5A</div>", "<div style=\"font-family:Cambria;font-size:17px;\">0.9A</div>", "<div style=\"font-family:Cambria;font-size:17px;\">1.5A</div>", "<div style=\"font-family:Cambria;font-size:17px;\">4.5A</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">E = 1.5V <br/> E = I(R+r) <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">I</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">E<hr size=\"1\" />R+r</td></tr></table></div> <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">1<hr size=\"1\" />r</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">1<hr size=\"1\" />1</td><td style=\"text-align:center;\">+</td><td style=\"text-align:center;\">1<hr size=\"1\" />1</td><td style=\"text-align:center;\">+</td><td style=\"text-align:center;\">1<hr size=\"1\" />1</td></tr></table></div> <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">1<hr size=\"1\" />r</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">3</td></tr></table></div> <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">r</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">1<hr size=\"1\" />3</td></tr></table></div> <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">I</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">1.5<hr size=\"1\" /><span style=\"position: relative;left:3px;top:-7px; font-size:15px;\">1</span>/<span style=\"position:relative;left:-3px;top:7px;font-size:15px;\">3</span>+<span style=\"position: relative;left:3px;top:-7px; font-size:15px;\">2</span>/<span style=\"position:relative;left:-3px;top:7px;font-size:15px;\">3</span></td></tr></table></div> <br/> I = 1.5A</div>", "topic": "ELECTRIC CELLS"}, {"id": "objective>Physics>1997>31", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A galvanometer of internal resistance 50Ω has a full scale deflection for a current of 5mA. What is the resistance required to covert it to a voltmeter with full scale deflection of 10V?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">1750Ω</div>", "<div style=\"font-family:Cambria;font-size:17px;\">1950Ω</div>", "<div style=\"font-family:Cambria;font-size:17px;\">2000Ω</div>", "<div style=\"font-family:Cambria;font-size:17px;\">2500Ω</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">I = 0.005A, R  = ?, r = 50Ω <br/> 10 = 0.005R + 50(0.005) <br/> 10 = 0.25 + 0.005R <br/> 0.005R = 9.75 <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">R</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">9.75<hr size=\"1\" />0.005</td></tr></table></div> <br/> R = 1950Ω</div>", "topic": "FORCE ON A CURRENT-CARRYING CONDUCTOR IN A MAGNETIC FIELD"}, {"id": "objective>Physics>1997>32", "question": "<div style=\"font-family:Cambria;font-size:17px;\">If 8 x 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">−2</span> J of work is required to move 100μC of charge from a point X to a point Y in an electrical circuit, the potential difference between X and Y is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">4.0 x 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span> V</div>", "<div style=\"font-family:Cambria;font-size:17px;\">4.0 x 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">4</span> V</div>", "<div style=\"font-family:Cambria;font-size:17px;\">8.0 x 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span> V</div>", "<div style=\"font-family:Cambria;font-size:17px;\">8.0 x 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-2</span> V</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\"><div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">V</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">W<hr size=\"1\" />Q</td></tr></table></div> <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">V</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">8×10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-2</span><hr size=\"1\" />100×10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-6</span></td></tr></table></div> <br/> V = 8.0 × 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span> V</div>", "topic": "CURRENT ELECTRICITY"}, {"id": "objective>Physics>1997>33", "question": "<div style=\"font-family:Cambria;font-size:17px;\">In a meter bridge experiment, two resistor 2Ω and 3Ω occupy the left and right gaps respectively. Find the balance point from the left side of the bridge</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">20cm</div>", "<div style=\"font-family:Cambria;font-size:17px;\">40cm</div>", "<div style=\"font-family:Cambria;font-size:17px;\">60cm</div>", "<div style=\"font-family:Cambria;font-size:17px;\">80cm</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Let the point be x <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">2<hr size=\"1\" />x</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">3<hr size=\"1\" />100−x</td></tr></table></div> <br/> making x subject of formula, <br/> 2(100 - x) = 3x <br/> 200 - 2x = 3x <br/> 200 = 3x + 2x <br/> 200 = 5x <br/> divide both side by 5 <br/> x = 40cm</div>", "topic": "CURRENT ELECTRICITY : METER BRIDGE"}, {"id": "objective>Physics>1997>34", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Two 50μF parallel plate capacitors are connected in series. The combined capacitor is then connected across a 100-V battery. The charge on each plate of the capacitor is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">5.00 x 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-5</span>C</div>", "<div style=\"font-family:Cambria;font-size:17px;\">2.50 x 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-3</span>C</div>", "<div style=\"font-family:Cambria;font-size:17px;\">1.25 x 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-3</span>C</div>", "<div style=\"font-family:Cambria;font-size:17px;\">1.00 x 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-2</span>C</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\"><div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">For</td><td style=\"text-align:center;\">series,</td><td style=\"text-align:center;\">C</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\"></td><td style=\"text-align:center;\">50×50<hr size=\"1\" />50+50</td></tr></table></div> <br/> C= 25μF <br/> Q = CV <br/> Q = 25 x 100 x 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-6</span> <br/> Q = 2.5 x 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-3</span>C</div>", "topic": "CAPACITORS : CAPACITORS IN SERIES AND PARALLEL"}, {"id": "objective>Physics>1997>35", "question": "<div style=\"font-family:Cambria;font-size:17px;\">What is the total electrical energy consumed by using an electric cooker rated 1000W for 5 hrs?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">5.3 x 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span>J</div>", "<div style=\"font-family:Cambria;font-size:17px;\">6.5 X 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span>J</div>", "<div style=\"font-family:Cambria;font-size:17px;\">1.8 X 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">7</span>J</div>", "<div style=\"font-family:Cambria;font-size:17px;\">2.3 X 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">7</span>J</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The total electrical energy (E) consumed by an electrical appliance is given by E = P*t, where P is the power rating of the appliance and t is the time for which the appliance is used. Therefore, E = 1000W * 5hrs = 5000Wh = 1.8 * 10^7 J (since 1Wh = 3600J). Therefore, the correct answer is 1.8 X 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">7</span>J.</div>", "topic": "ELECTRICAL ENERGY AND POWER"}, {"id": "objective>Physics>1997>36", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The power dissipated in an a.c. circuit with an r.m.s, current of 5A, r.m.s voltage of 10V and a phase angle of 60<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">o</span> is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">25W</div>", "<div style=\"font-family:Cambria;font-size:17px;\">50W</div>", "<div style=\"font-family:Cambria;font-size:17px;\">120W</div>", "<div style=\"font-family:Cambria;font-size:17px;\">125W</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">P = IVcosΦ <br/> P = 5 × 10 × cos60<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">∘</span> <br/> P = 50(0.5) = 25W</div>", "topic": "SIMPLE A. C. CIRCUITS"}, {"id": "objective>Physics>1997>37", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The voltage of the domestic electric supply is represented by the equation V = 311 sin314.2t. Determine the frequency of the a.c. supply [π = 3.142]</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">50.0Hz</div>", "<div style=\"font-family:Cambria;font-size:17px;\">100.0Hz</div>", "<div style=\"font-family:Cambria;font-size:17px;\">311.0Hz</div>", "<div style=\"font-family:Cambria;font-size:17px;\">314.2Hz</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">V = 311 sin314.2t comparing with <br/> V = V<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">0</span>sin2πft <br/> 2πft = 314.2t <br/> 2πf = 314.2 <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">f</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">314.2<hr size=\"1\" />2π</td></tr></table></div> <br/> f = 50Hz</div>", "topic": "SIMPLE A. C. CIRCUITS"}, {"id": "objective>Physics>1997>38", "question": "<div style=\"font-family:Cambria;font-size:17px;\">In a purely inductive circuit, the current</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">lags behind the voltage in phase by 90<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">o</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">leads the voltage in phase by 90<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">o</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">is in the same phase with the voltage</div>", "<div style=\"font-family:Cambria;font-size:17px;\">leads the voltage by 180<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">o</span></div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">In a purely inductive circuit, the current lags behind the voltage by 90 degrees. This is because an inductor resists changes in current, causing a delay or 'lag' between the voltage and current waveforms. This is a fundamental property of inductive circuits and is represented by the phase difference of 90 degrees. Therefore, the correct answer is option 1.</div>", "topic": "SIMPLE A. C. CIRCUITS : INDUCTOR - INDUCTIVE REACTANCE"}, {"id": "objective>Physics>1997>39", "question": "<div style=\"font-family:Cambria;font-size:17px;\">One of the features of the fission process is that</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">its products are not radioactive</div>", "<div style=\"font-family:Cambria;font-size:17px;\">it leads to chain reaction</div>", "<div style=\"font-family:Cambria;font-size:17px;\">neutrons are not released</div>", "<div style=\"font-family:Cambria;font-size:17px;\">the sum of the masses of the reactants equals the sum of masses of the products</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Nuclear fission, subdivision of a heavy atomic nucleus, such as that of uranium or plutonium, into two fragments of roughly equal mass. The process is accompanied by the release of a large amount of energy. In nuclear fission the nucleus of an atom breaks up into two lighter nuclei.</div>", "topic": "ELEMENTARY MODERN PHYSICS : FUSION AND FISSION"}, {"id": "objective>Physics>1997>40", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The graphite rods surrounding the uranium fuel rods in a nuclear reactor, are used to</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">absorb the neutrons and hence halt the nuclear process</div>", "<div style=\"font-family:Cambria;font-size:17px;\">create the neutrons and hence slow up the nuclear process</div>", "<div style=\"font-family:Cambria;font-size:17px;\">slowdown the neutrons and hence slow up the nuclear process</div>", "<div style=\"font-family:Cambria;font-size:17px;\">speed up the neutrons and hence speed up the nuclear process</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Graphite rods are used as a moderator. Moderator is a material used in a nuclear reactor to slow down the neutrons produced from fission. By slowing the neutrons down the probability of neutron interacting with Uranium-235 nuclei is greatly increased thereby maintaining the chain reaction</div>", "topic": "ELEMENTARY MODERN PHYSICS : FUSION AND FISSION"}, {"id": "objective>Physics>1997>41", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A galvanometer of internal resistance 50 Ohms has a full scale deflection for current of 5 mA. What is the resistance required to convert it to a voltmeter with fullscale deflection of 10V?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">1750 Ohms</div>", "<div style=\"font-family:Cambria;font-size:17px;\">1950 Ohms</div>", "<div style=\"font-family:Cambria;font-size:17px;\">2000 Ohms</div>", "<div style=\"font-family:Cambria;font-size:17px;\">2500 Ohms</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">voltage drop at the internal resistance = 50(0.005) = 0.25V <br/> 10 - 0.25 = 9.75V <br/> R = 9.75/0.005 = 1950 Ohms</div>", "topic": "FORCE ON A CURRENT-CARRYING CONDUCTOR IN A MAGNETIC FIELD"}, {"id": "objective>Physics>1997>42", "question": "<div style=\"font-family:Cambria;font-size:17px;\">If 8 X 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-2</span>J of work is required to move 100 μC of charge from a point X to a point Y in an electrical circuit, the potential difference between X and Y</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">4.0 X 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span> V</div>", "<div style=\"font-family:Cambria;font-size:17px;\">4.0 X 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">4</span> V</div>", "<div style=\"font-family:Cambria;font-size:17px;\">8.0 X 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span> V</div>", "<div style=\"font-family:Cambria;font-size:17px;\">8.0 X 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">4</span> V</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">W = QV <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">V</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">W<hr size=\"1\" />Q</td></tr></table></div> <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">V</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">8×10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-2</span><hr size=\"1\" />10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-4</span></td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">8</td><td style=\"text-align:center;\">×</td><td style=\"text-align:center;\">10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span>V</td></tr></table></div></div>", "topic": "CURRENT ELECTRICITY"}, {"id": "objective>Physics>1997>43", "question": "<div style=\"font-family:Cambria;font-size:17px;\"><img src=\"data:image/jpeg;base64,\" style=\"position:relative;max-width:100%;\"/> <br/> For what value of θ are the forces in the diagram above in equilibirium </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">15<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">∘</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">30<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">∘</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">45<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">∘</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">60<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">∘</span></div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">∑fy = 0 <br/> 12cosθ = 6 <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">cosθ</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">6<hr size=\"1\" />12</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">0.5</td></tr></table></div> <br/> θ = cos<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-1</span>0.5 = 60<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">∘</span></div>", "topic": "EQUILIBRIUM OF FORCES : CONDITIONS FOR EQUILIBRIUM OF RIGID BODIES UNDER THE ACTION OF PARALLEL AND NON-PARALLEL FORCES"}, {"id": "objective>Physics>1997>44", "question": "<div style=\"font-family:Cambria;font-size:17px;\"><img src=\"data:image/jpeg;base64,\" style=\"position:relative;max-width:100%;\"/> <br/> The fig above shows a block of mass m sliding down a rough inclined plane QP at angle θ . The forces acting on the block along QP are </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">mg sinθ and the normal reaction</div>", "<div style=\"font-family:Cambria;font-size:17px;\">mg sinθ and the force of friction</div>", "<div style=\"font-family:Cambria;font-size:17px;\">mg cosθ and the force reaction</div>", "<div style=\"font-family:Cambria;font-size:17px;\">mg cosθ and the normal reaction</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The forces acting on the block along QP are  mg sinθ and the force of friction. <br/>  <br/> <img src=\"1997/phyans44.png\" style=\"position:relative;max-width:100%;\"/></div>", "topic": "FRICTION"}, {"id": "objective>Physics>1997>45", "question": "<div style=\"font-family:Cambria;font-size:17px;\"><img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/> <br/> A uniform light beam XZ is Hinged at X and kept in equilibrium by the forces T and F as shown in the diagram above. if XO = 20m and OY = 30cm, express T in terms of F </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\"><div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">T</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">2√3<hr size=\"1\" />3</td></tr></table></div></div>", "<div style=\"font-family:Cambria;font-size:17px;\">T= 2F</div>", "<div style=\"font-family:Cambria;font-size:17px;\"><div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\"></td><td style=\"text-align:center;\">T</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">5&radic;<span style=\"margin: 0;padding:0;border-top:solid black 1px;\">3&nbsp;</span>F<hr size=\"1\" />3</td></tr></table></div></div>", "<div style=\"font-family:Cambria;font-size:17px;\">T = 5F</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Taking the moment at X <br/> Tsin30 × 20 = F(50) <br/> 0.5T(20) = 50F <br/> 10T = 50F <br/> T = 5F <br/> </div>", "topic": "EQUILIBRIUM OF FORCES : PRINCIPLES OF MOMENTS"}, {"id": "objective>Physics>1997>46", "question": "<div style=\"font-family:Cambria;font-size:17px;\"><img src=\"data:image/jpeg;base64,\" style=\"position:relative;max-width:100%;\"/> <br/> For a rough inclined plane on which lies a body of weight W, the angle θ in the diagram above becomes the angle of friction if </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">tan θ = coefficient of static friction</div>", "<div style=\"font-family:Cambria;font-size:17px;\">cos θ = coefficient of dynamic friction</div>", "<div style=\"font-family:Cambria;font-size:17px;\">sin θ = coefficient of sliding friction</div>", "<div style=\"font-family:Cambria;font-size:17px;\">sec θ = limiting frictional force</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">tan θ = <span class = \"katex\"><span class = \"katex-mathml\"><math xmlns = \"http://www.w3.org/1998/Math/MathML\"><semantics><mrow><mfrac><mrow><mi>W</mi><mi>sin</mi><mo>⁡</mo><mrow><mo fence = \"true\">(</mo><mi>θ</mi><mo fence = \"true\">)</mo></mrow></mrow><mrow><mi>W</mi><mi>cos</mi><mo>⁡</mo><mrow><mo fence = \"true\">(</mo><mi>θ</mi><mo fence = \"true\">)</mo></mrow></mrow></mfrac></mrow><annotation encoding = \"application/x-tex\">\\frac{W\\sin{\\left(θ\\right)}}{W\\cos{\\left(θ\\right)}}</annotation></semantics></math></span><span class = \"katex-html\" aria-hidden = \"true\"><span class = \"base\"><span class = \"strut\" style = \"height:1.53em;vertical-align:-0.52em;\"></span><span class = \"mord\"><span class = \"mopen nulldelimiter\"></span><span class = \"mfrac\"><span class = \"vlist-t vlist-t2\"><span class = \"vlist-r\"><span class = \"vlist\" style = \"height:1.01em;\"><span style = \"top:-2.655em;\"><span class = \"pstrut\" style = \"height:3em;\"></span><span class = \"sizing reset-size6 size3 mtight\"><span class = \"mord mtight\"><span class = \"mord mathnormal mtight\" style = \"margin-right:0.13889em;\">W</span><span class = \"mspace mtight\" style = \"margin-right:0.1952em;\"></span><span class = \"mop mtight\"><span class = \"mtight\">c</span><span class = \"mtight\">o</span><span class = \"mtight\">s</span></span><span class = \"mspace mtight\" style = \"margin-right:0.1952em;\"></span><span class = \"mord mtight\"><span class = \"minner mtight\"><span class = \"mopen mtight delimcenter\" style = \"top:0em;\"><span class = \"mtight\">(</span></span><span class = \"mord mathnormal mtight\" style = \"margin-right:0.02778em;\">θ</span><span class = \"mclose mtight delimcenter\" style = \"top:0em;\"><span class = \"mtight\">)</span></span></span></span></span></span></span><span style = \"top:-3.23em;\"><span class = \"pstrut\" style = \"height:3em;\"></span><span class = \"frac-line\" style = \"border-bottom-width:0.04em;\"></span></span><span style = \"top:-3.485em;\"><span class = \"pstrut\" style = \"height:3em;\"></span><span class = \"sizing reset-size6 size3 mtight\"><span class = \"mord mtight\"><span class = \"mord mathnormal mtight\" style = \"margin-right:0.13889em;\">W</span><span class = \"mspace mtight\" style = \"margin-right:0.1952em;\"></span><span class = \"mop mtight\"><span class = \"mtight\">s</span><span class = \"mtight\">i</span><span class = \"mtight\">n</span></span><span class = \"mspace mtight\" style = \"margin-right:0.1952em;\"></span><span class = \"mord mtight\"><span class = \"minner mtight\"><span class = \"mopen mtight delimcenter\" style = \"top:0em;\"><span class = \"mtight\">(</span></span><span class = \"mord mathnormal mtight\" style = \"margin-right:0.02778em;\">θ</span><span class = \"mclose mtight delimcenter\" style = \"top:0em;\"><span class = \"mtight\">)</span></span></span></span></span></span></span></span><span class = \"vlist-s\">​</span></span><span class = \"vlist-r\"><span class = \"vlist\" style = \"height:0.52em;\"><span></span></span></span></span></span><span class = \"mclose nulldelimiter\"></span></span></span></span></span> = coefficient of static friction</div>", "topic": "FRICTION"}, {"id": "objective>Physics>1997>47", "question": "<div style=\"font-family:Cambria;font-size:17px;\"><img src=\"data:image/jpeg;base64,\" style=\"position:relative;max-width:100%;\"/> <br/> The diagram above shows two wave forms P and Q at a particular instant in time. the two waves will interface </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">destructively to produce a wave of larger amplitude</div>", "<div style=\"font-family:Cambria;font-size:17px;\">destructively to produce a wave of smaller amplitude</div>", "<div style=\"font-family:Cambria;font-size:17px;\">constructively to produce a wave of larger amplitude</div>", "<div style=\"font-family:Cambria;font-size:17px;\">constructively to produce a wave of smaller amplitude</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Since waves P and Q are in phase, it means that the crests of wave P align with the crests of wave Q, and similarly, the troughs of wave P align with the troughs of wave Q. In this scenario, the interference that occurs is known as \"constructive interference.\" <br/>  <br/> In constructive interference, the amplitudes of the two waves add together. Since wave P has a larger amplitude, its contribution dominates the resultant wave. As a result, the combined wave will have a larger amplitude than either wave P or wave Q individually. <br/>  <br/> Mathematically, if we denote the amplitudes of waves P and Q as A<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">P</span> and A<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">Q</span> respectively, and the resultant amplitude as A<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">resultant</span> , then: <br/>  <br/> A<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">resultant</span> = A<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">P</span> + A<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">Q</span> <br/>  <br/> This means that the amplitude of the resulting wave is the sum of the amplitudes of the individual waves. <br/>  <br/> Visually, on a graph representing the waves, the peaks of wave P and wave Q align perfectly, leading to higher peaks in the resulting wave. This constructive interference results in an amplification of the wave's intensity where the waves overlap.</div>", "topic": "WAVES : CHARACTERISTICS/PROPERTIES"}, {"id": "objective>Physics>1997>48", "question": "<div style=\"font-family:Cambria;font-size:17px;\"><img src=\"data:image/jpeg;base64,\" style=\"position:relative;max-width:100%;\"/> <br/> When the sun, moon and the earth are as shown in the diagram above an observer standing in X is in </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Penumbra and sees a partial eclipse</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Penumbra and sees a total eclipse</div>", "<div style=\"font-family:Cambria;font-size:17px;\">umbra and sees a partial eclipse</div>", "<div style=\"font-family:Cambria;font-size:17px;\">umbra and sees a total eclipse</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">An observer standing in X is in penumbra and sees a partial eclipse.</div>", "topic": "LIGHT ENERGY : PROPAGATION OF LIGHT"}, {"id": "objective>Physics>1997>49", "question": "<div style=\"font-family:Cambria;font-size:17px;\"><img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/> <br/> In the diagram above, which of the angles θ<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span> , θ<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span> , θ<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span> and θ<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">4</span> is the angle of deviation of the ray of light passing through the glass prism XYZ? </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">θ<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">θ<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">θ<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">θ<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">4</span></div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The angle of deviation of the ray of light passing through the glass prism XYZ is θ<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span>.</div>", "topic": "REFRACTION OF LIGHT THROUGH : GLASS PRISM"}];
